// for binary debug
function dec2bin(dec) {
  return (dec >>> 0).toString(2);
}

/**
* @param {string | number} chan
* @param {string | number} val
*/
function fnISCdigital (chan,val){
    let bytes = [];
    chan = Number.parseInt(chan, 10) + Number(env.get("ISCoffset")) - 1
    val = Number.parseInt(val,10)

    let idx = (((chan << 1) & 0x1F00) | (chan & 0x7f))
    let an = (((val & 0x01) ^ 0x01) << 13)
    let X = 0x8000 | idx | an

    bytes.push((X >> 8) & 0x000000ff)
    bytes.push(X & 0x000000ff)

    // return array
    return (bytes)
}

// converts val fro <0-100> to <0-65535>
/**
* @param {string | number} chan
* @param {string | number} val
*/
function fnISCanalog (chan,val){
    let bytes = [];
    chan = Number.parseInt(chan)-1
    val = Number.parseInt(val) | 0
    let idx = (((chan << 1) & 0x0700) | (chan & 0x7f)) << 16
    let an = ((val & 0xC000) << 14)  | ((val & 0x3f80) << 1) | (val & 0x7f) 
    let X = 0xC0000000 | idx | an

    /*
    node.warn({
        "chan: ":dec2bin(chan),
        "val: ":dec2bin(val),
        "idx: ":dec2bin(idx),
        "an: ":dec2bin(an),
        "ISC: ":dec2bin(X)

    })
    */

    bytes.push((X >> 24) & 0x000000ff)
    bytes.push((X >> 16) & 0x000000ff)
    bytes.push((X >> 8) & 0x000000ff)
    bytes.push(X & 0x000000ff)

    // return array
    return (bytes)
}
/**
* @param {string | number} chan
* @param {string | number} val
*/
function fnISCserial (chan,val){
    let bytes = [];
    chan = Number.parseInt(chan)-1

    let idx = (((chan << 1) & 0x0700) | (chan & 0x7f))
    let X = 0xC800 | idx

    bytes.push((X >> 8) & 0x000000ff)
    bytes.push(X & 0x000000ff)

    for (let i=0; i<val.length; i++){
        bytes.push(val.charCodeAt(i))
    }    

    bytes.push(0xff)

    // return array
    return (bytes)
}

let ss
switch (msg.topic){
    case "analog":
        ss = fnISCanalog(msg.channel,msg.payload)        
        msg.payload = Buffer.from(ss)
        return msg;        
    case "digital":
        ss = fnISCdigital(msg.channel,msg.payload) 
        msg.payload = Buffer.from(ss)
        return msg; 
    case "serial":
        ss = fnISCserial(msg.channel,msg.payload) 
        msg.payload = Buffer.from(ss)
        return msg;        
}

// collect buffer bytes
let RX=flow.get("ISCrx")
if (RX){
    let arr = [RX, msg.payload];
    RX = Buffer.concat(arr);    
}
else{
    RX = Buffer.from(msg.payload);
}

// node.warn({"BUFFER: ":RX})
let ns = 0 // new start of remaining buffer
let newmsg={}


let msgs=[]

for (let i=0; i<RX.length; i++){

    let newmsg={}

    // digitals
    if ((RX[i] & 0xC0) == 0x80){
        if ((RX.length-i) >= 2){
            let data={
                "type":"digital",
                "chan":(RX[i] & 0x1f)<<8 | (RX[i+1] & 0x7f)+1-Number(env.get("ISCoffset")),
                "value":(RX[i] & 0x20)>>5 ^ 0x01
            }
            newmsg.payload=data.value
            newmsg.channel=data.chan
            newmsg.topic=data.type

            msgs.push(newmsg)
            node.send(newmsg)

            i=i+1 // advance pointer to next message
            ns=i
        }
    }

    //analogs
    else if ((RX[i] & 0xC8) == 0xC0){
        if ((RX.length-i) >= 4){
            let data={
                "type":"analog",
                "chan":(RX[i] & 0x07)<<8 | (RX[i+1] & 0x7f)+1,
                "value":((RX[i] & 0x30) << 10 | (RX[i+2] & 0x7f) << 7 | (RX[i+3] & 0x7f)) | 0
            }

            newmsg.payload=data.value
            newmsg.channel=data.chan
            newmsg.topic=data.type

            msgs.push(newmsg)
            node.send(newmsg)
            i=i+3 // advance pointer to next message
            ns=i
        }
    }

    //strings
    else if ((RX[i] & 0xC8) == 0xC8){
        var eos = RX.indexOf(0xff,i+1)
        if (eos >= 0){
            let data={
                "type":"serial",
                "chan":(RX[i] & 0x07)<<8 | (RX[i+1] & 0x7f)+1,
                "value":RX.slice(i+2,eos).toString()
            }

            newmsg.payload=data.value
            newmsg.channel=data.chan
            newmsg.topic=data.type


            msgs.push(newmsg)
            node.send(newmsg)
            i=eos // advance pointer to next message
            ns=i
        }
    }
}

// keep only the remaining bytes in buffer from the end of the last complete message
if (RX.length==ns){
    flow.set("ISCrx",null) // no bytes left, set null
}
else{
    flow.set("ISCrx",RX.slice(ns+1,RX.length)) // preserve remainder
}

