            let nd=scouts[i].state.node
            let s=nd.split("/")
            let path = ""
            // generate sub nodes
            for (let p=0;p<s.length;p++){
                path=path+s[p]
                //node.warn({"path: ":path})                
                const found = nodes.some((/** @type {{ node: string; }} */ el) => el.node === path)

                if (!found){
                    const members = scouts.reduce((/** @type {number} */ accumulator, /** @type {{ id: string; }} */ obj) => {

                        if (obj.state.hasOwnProperty("node")) {
                            /*
                            node.warn({
                                "node path ": obj.state.node,
                                "path ": path,
                                "obj.state.node.substring(0, path.length)": obj.state.node.substring(0, path.length),
                                "member? ": (obj.state.node.substring(0, path.length) === path)
                            })
                            */
                            if (obj.state.node.substring(0, path.length) === path) {
                                return accumulator + 1;
                            }
                        }

                        return accumulator;
                    }, 0);

                    nodes.push({
                        "node":path,
                        "join":0,
                        "isChecked":false,
                        "announcing":0, // count of all scouts currently announcing on this node
                        "members":members
                    })
                    nd={
                        "payload": path,
                        "channel": nodes.length + 20,
                        "topic":"serial"
                    }
                    node.send([null,null,nd]);            

                }
                path=path+"/"
            }
        }
    }

    if (nodes.length) {

        // track count of scouts announcing per node
        if (msg.payload.hasOwnProperty("nod")) {
            let topic_node = msg.payload.nod.split("/")
            if (topic_node[1] == "$group") {
                if (msg.payload.hasOwnProperty("sta")) {
                    let path=""
                    for (let i=2;i<topic_node.length-1;i++){
                        path=path+topic_node[i];
                        if (i < topic_node.length - 2)
                            path = path +"/";
