// Map linear fader [0,1] to Teensy gain [0,1] with (roughly) linear dB steps
// Slow-rise potentiometer curve: most adjustment in 0–80%, steeper near the top
function volumeCurve(x, steepness = 6, midpoint = 0.75) {
    if (x <= 0) return 0;
    if (x >= 1) return 1;

    // logistic S-curve normalized from 0 → 1
    const k = steepness;     // higher = steeper upper half
    const m = midpoint;      // where the curve "bends"

    const y = 1 / (1 + Math.exp(-k * (x - m)));

    // normalize logistic to 0–1 range
    const yMin = 1 / (1 + Math.exp(k * m));
    const yMax = 1 / (1 + Math.exp(-k * (1 - m)));
    const norm = (y - yMin) / (yMax - yMin);

    return parseFloat(norm.toFixed(8));
}

